import java.awt.*;
import javax.swing.*;

public class RainDisplay extends JPanel {
    private static final int WIDTH = 800;
    private static final int HEIGHT = 600;
    private static final int NUM_RAINDROPS = 100;

    private Raindrop[] raindrops;

    public RainDisplay() {
        setPreferredSize(new Dimension(WIDTH, HEIGHT));
        setBackground(Color.BLACK);
        raindrops = new Raindrop[NUM_RAINDROPS];
        for (int i = 0; i < NUM_RAINDROPS; i++) {
            raindrops[i] = new Raindrop();
        }
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);
        Graphics2D g2d = (Graphics2D) g;

        for (Raindrop raindrop : raindrops) {
            raindrop.update();
            g2d.setColor(Color.WHITE);
            g2d.fillOval(raindrop.x, raindrop.y, 2, 10);
        }

        repaint();
    }

    private class Raindrop {
        private int x;
        private int y;
        private double speed;

        public Raindrop() {
            this.x = (int) (Math.random() * WIDTH);
            this.y = (int) (Math.random() * HEIGHT);
            this.speed = Math.random() * 5 + 1;
        }

        public void update() {
            y += speed;
            if (y > HEIGHT) {
                y = 0;
                x = (int) (Math.random() * WIDTH);
            }
        }
    }

    public static void main(String[] args) {
        JFrame frame = new JFrame("Rain Animation");
        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        frame.getContentPane().add(new RainDisplay());
        frame.pack();
        frame.setLocationRelativeTo(null);
        frame.setVisible(true);
    }
}

